// FIX: Execute Command descarta o binário do Webhook.
// Recupera o binário original para o próximo nó poder salvar o arquivo.
const webhookItem = $('Webhook').first();
return [{
  json: webhookItem.json,
  binary: webhookItem.binary
}];

const raw = $json.stdout;

if (!raw) {
  throw new Error('Nenhum stdout recebido do OCR');
}

const data = JSON.parse(raw);

if (data.erro) {
  throw new Error('Erro no OCR: ' + data.erro);
}

return [{ json: { texto: data.texto } }];

let texto = $json.texto || '';

// Junta palavras quebradas no fim da linha com hífen
texto = texto.replace(/-\n/g, '');

// Remove quebras de linha duplicadas
texto = texto.replace(/\n{2,}/g, '\n');

// Remove espaços e tabs duplicados
texto = texto.replace(/[ \t]+/g, ' ');

// Remove linhas com apenas lixo (menos de 3 chars não-alfanuméricos)
texto = texto.replace(/\n[^\wÀ-ÿ]{1,3}\n/g, '\n');

// Trim geral
texto = texto.trim();

return [{ json: { texto_limpo: texto } }];

// Extrai o SQL da resposta da IA
// O nó OpenAI pode retornar o conteúdo em campos diferentes dependendo da versão
const content =
  $json.content ||
  $json.message?.content ||
  $json.choices?.[0]?.message?.content ||
  $json.text ||
  '';

if (!content) {
  throw new Error(
    'Não foi possível extrair o SQL da resposta da IA.\nJSON recebido: ' +
    JSON.stringify($json, null, 2)
  );
}

// Remove blocos de código markdown caso a IA os inclua (```sql ... ```)
let sql = content.trim();
sql = sql.replace(/```sql\s*/gi, '').replace(/```\s*/g, '').trim();

// Validação básica
if (!sql.toUpperCase().startsWith('INSERT')) {
  throw new Error('A IA não retornou um INSERT válido.\nResposta: ' + sql);
}

return [{ json: { sql_insert: sql } }];

const body = $json.body || $json;
const vaga  = body.vaga  || '';
const cargo = body.cargo || '';
const local = body.localizacao || '';
const skill = body.habilidade  || '';
const limite = Math.min(parseInt(body.limite) || 10, 50);

const esc = s => (s || '').replace(/'/g, "''");

// Coleta todos os termos de todos os filtros, separados por virgula
const allTerms = [cargo, local, skill]
  .join(',')
  .split(',')
  .map(t => t.trim())
  .filter(t => t.length > 0);

// Todas as colunas de texto a pesquisar
const cols = [
  'nome_completo',
  'cargo_pretendido',
  'habilidades',
  'localizacao',
  'experiencia_resumida',
  'formacao',
  'email'
];

let where = '';
if (allTerms.length > 0) {
  const termClauses = allTerms.map(term => {
    const colClauses = cols.map(col =>
      `COALESCE(${col}, '') ILIKE '%${esc(term)}%'`
    );
    return '(' + colClauses.join(' OR ') + ')';
  });
  where = 'WHERE ' + termClauses.join(' OR ');
}

const sql = `SELECT COALESCE(json_agg(row_to_json(c)), '[]'::json) AS candidatos FROM (SELECT * FROM candidatos ${where} LIMIT ${limite}) c`;

return [{ json: { sql, vaga, limite } }];

let candidatos = $json.candidatos;
if (typeof candidatos === 'string') {
  try { candidatos = JSON.parse(candidatos); } catch(e) { candidatos = []; }
}
if (!Array.isArray(candidatos)) { candidatos = []; }
return [{ json: { candidatos } }];

const candidatos = $json.candidatos;
const vaga = $('Montar SQL').first().json.vaga;

const candidatosStr = candidatos.map((c, i) =>
  `[${i + 1}] ID:${c.id} | Nome:${c.nome_completo || 'N/A'} | Cargo:${c.cargo_pretendido || 'N/A'} | Habilidades:${c.habilidades || 'N/A'} | Local:${c.localizacao || 'N/A'} | Experiencia:${(c.experiencia_resumida || '').substring(0, 150)}`
).join('\n');

return [{ json: {
  vaga,
  candidatos_str: candidatosStr,
  candidatos_json: JSON.stringify(candidatos)
}}];

const content =
  $json.content ||
  ($json.message && $json.message.content) ||
  ($json.choices && $json.choices[0] && $json.choices[0].message && $json.choices[0].message.content) ||
  '[]';

const raw = content.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();

let rankings;
try {
  rankings = JSON.parse(raw);
} catch (e) {
  throw new Error('IA retornou JSON invalido: ' + raw.substring(0, 200));
}

const candidatos = JSON.parse($('Preparar para IA').first().json.candidatos_json);

const resultado = rankings.map(r => {
  const c = candidatos[r.indice - 1];
  if (!c) return null;
  return Object.assign({}, c, { score: r.score, justificativa: r.justificativa });
}).filter(Boolean);

return [{ json: { candidatos: resultado } }];
